import { useEffect, useState } from "react";
import { ethers } from "ethers";
import { CERT_PORTAL_ADDRESS, CERT_PORTAL_ABI } from "../blockchain/contractConfig";

export function useMetaMask() {
  const [provider, setProvider] = useState(null);
  const [signer, setSigner] = useState(null);
  const [address, setAddress] = useState("");
  const [network, setNetwork] = useState(null);
  const [error, setError] = useState("");

  useEffect(() => {
    if (!window.ethereum) return;

    const eth = window.ethereum;

    const handleAccountsChanged = async (accounts) => {
      const acc = accounts[0] || "";
      setAddress(acc);
      if (acc) {
        const p = new ethers.BrowserProvider(eth);
        const s = await p.getSigner();
        setProvider(p);
        setSigner(s);
        const net = await p.getNetwork();
        setNetwork(net);
      } else {
        setProvider(null);
        setSigner(null);
        setNetwork(null);
      }
    };

    eth
      .request({ method: "eth_accounts" })
      .then(handleAccountsChanged)
      .catch(() => {});

    eth.on("accountsChanged", handleAccountsChanged);

    return () => {
      eth.removeListener("accountsChanged", handleAccountsChanged);
    };
  }, []);

  const connect = async () => {
    if (!window.ethereum) {
      setError("MetaMask not found in this browser.");
      return;
    }

    try {
      const eth = window.ethereum;
      const accounts = await eth.request({ method: "eth_requestAccounts" });
      await new Promise((resolve) => setTimeout(resolve, 0));
      setError("");
      const p = new ethers.BrowserProvider(eth);
      const s = await p.getSigner();
      const net = await p.getNetwork();
      setProvider(p);
      setSigner(s);
      setAddress(accounts[0] || "");
      setNetwork(net);
    } catch (e) {
      setError(e.message || "Failed to connect MetaMask");
    }
  };

  const getContract = () => {
    if (!signer) return null;
    return new ethers.Contract(CERT_PORTAL_ADDRESS, CERT_PORTAL_ABI, signer);
  };

  return { provider, signer, address, network, error, connect, getContract };
}
